const body = $input.first().json.body;
const message = body.business_message;
const text = message.text.toLowerCase();
const chatId = message.chat.id;
const businessId = message.business_connection_id;
const messageId = message.message_id;

let mode = 'top'; 

if (text.includes('биткоин') || text.includes('bitcoin') || text.includes('btc')) {
  mode = 'single';
  var symbol = 'BTCUSDT';
  var coinName = 'Bitcoin (BTC)';
} else if (text.includes('эфир') || text.includes('ethereum') || text.includes('eth')) {
  mode = 'single';
  var symbol = 'ETHUSDT';
  var coinName = 'Ethereum (ETH)';
} else if (text.includes('солана') || text.includes('solana') || text.includes('sol')) {
  mode = 'single';
  var symbol = 'SOLUSDT';
  var coinName = 'Solana (SOL)';
} else if (text.includes('доги') || text.includes('dogecoin') || text.includes('doge')) {
  mode = 'single';
  var symbol = 'DOGEUSDT';
  var coinName = 'Dogecoin (DOGE)';
} else if (text.includes('тон') || text.includes('toncoin') || text.includes('ton')) {
  mode = 'single';
  var symbol = 'TONUSDT';
  var coinName = 'Toncoin (TON)';
}

return [{
  chat_id: chatId,
  mode: mode,
  symbol: symbol,
  coin_name: coinName,
  business_connection_id: businessId,
  reply_to_message_id: messageId
}];

const items = $input.all();
const originalData = $('Parse Crypto Request').item.json;

let tickers = [];
for (const item of items) {
  if (item.json && item.json.symbol) {
    tickers.push(item.json);
  }
}

const topCoinsOrder = [
  'BTC', 'ETH', 'BNB', 'XRP', 'SOL', 'ADA', 'DOGE', 'TRX', 'LINK', 'TON'
];

const tickerMap = {};
for (const ticker of tickers) {
  if (ticker && ticker.symbol) {
    const symbol = ticker.symbol.replace('USDT', '');
    tickerMap[symbol] = ticker;
  }
}

const results = [];
for (const coin of topCoinsOrder) {
  if (tickerMap[coin]) {
    const ticker = tickerMap[coin];
    results.push({
      name: coin,
      price: parseFloat(ticker.lastPrice).toFixed(2),
      change: parseFloat(ticker.priceChangePercent).toFixed(2)
    });
  }
}

if (results.length === 0) {
  return [{
    chat_id: originalData.chat_id,
    text: "❌ Not found.",
    business_connection_id: originalData.business_connection_id,
    reply_to_message_id: originalData.reply_to_message_id
  }];
}

let text = `💰 *Rates (24h)*\n\n`;
for (let i = 0; i < results.length; i++) {
  const coin = results[i];
  const trend = coin.change >= 0 ? '📈' : '📉';
  const changeSign = coin.change >= 0 ? '+' : '';
  text += `${i+1}. *${coin.name}*: ${trend} ${coin.price} USDT (${changeSign}${coin.change}%)\n`;
}

return [{
  chat_id: originalData.chat_id,
  text: text,
  parse_mode: "Markdown",
  business_connection_id: originalData.business_connection_id,
  reply_to_message_id: originalData.reply_to_message_id
}];
